import React,{useState,createContext} from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Topic1 from './components/Topic1/Topic1';
import Topic2 from './components/Topic2/Topic2';
import Home from './components/Home/Home';
export const MyContext = createContext<number>(2000);

function App() {
  return (
    <div>
      <ul>
          <li><a href='/topic1'>Topic1</a></li>
          <li><a href='/topic2'>Topic2</a></li>
          <li><a href='/'>Home</a></li>
      </ul>
      <Router>
          <Routes>
              <Route path='/' element={<Home />} />
              <Route path='/topic1' element={<Topic1 />} />
              <Route path='/topic2' element={<Topic2 />} />
          </Routes>
      </Router>
    </div>
  );
}

export default App;
